import { Component, OnInit, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ActivatedRoute, Router, RouterLink } from '@angular/router';
import { Item } from '../../core/models';

/**
 * Item create/edit form (manager only). The same component serves `items/new`
 * and `items/:id/edit`; presence of an :id switches to edit mode and pre-fills
 * from mock data (the service_agent stage will fetch the real item).
 */
@Component({
  selector: 'app-item-form',
  standalone: true,
  imports: [CommonModule, FormsModule, RouterLink],
  templateUrl: './item-form.component.html',
  styleUrl: './item-form.component.css',
})
export class ItemFormComponent implements OnInit {
  readonly editId = signal<string | null>(null);
  readonly saving = signal(false);
  readonly error = signal<string | null>(null);

  // Mock records for edit-mode pre-fill.
  readonly items = signal<Item[]>([
    { id: 'i1', sku: 'SKU-1001', name: 'Steel Bolt M6', unit: 'pcs', reorderAt: 100,
      description: 'Zinc-plated hex bolt, 6mm thread.' },
    { id: 'i2', sku: 'SKU-1002', name: 'Copper Wire 2mm', unit: 'm', reorderAt: 200,
      description: 'Bare copper wire, 2mm gauge, sold by the metre.' },
  ]);

  model = { sku: '', name: '', description: '', unit: 'pcs', reorderAt: 0 };

  constructor(
    private route: ActivatedRoute,
    private router: Router,
  ) {}

  get isEdit(): boolean {
    return this.editId() !== null;
  }

  ngOnInit(): void {
    const id = this.route.snapshot.paramMap.get('id');
    if (id) {
      this.editId.set(id);
      const existing = this.items().find((it) => it.id === id);
      if (existing) {
        this.model = {
          sku: existing.sku,
          name: existing.name,
          description: existing.description ?? '',
          unit: existing.unit,
          reorderAt: existing.reorderAt,
        };
      }
    }
  }

  submit(): void {
    if (!this.model.sku || !this.model.name || !this.model.unit) {
      this.error.set('SKU, name and unit are required.');
      return;
    }
    this.error.set(null);
    this.saving.set(true);
    // Mock persist — navigate back to the list.
    this.router.navigate(['/']);
  }

  cancel(): void {
    this.router.navigate(['/']);
  }
}
